        // On the first call to nonReentrant, _status will be NOT_ENTERED
        if (_status == ENTERED) {
            revert ReentrancyGuardReentrantCall();
        }

        // Any calls to nonReentrant after this point will fail
        _status = ENTERED;
    }

    function _nonReentrantAfter() private {
        // By storing the original value once again, a refund is triggered (see
        // https://eips.ethereum.org/EIPS/eip-2200)
        _status = NOT_ENTERED;
    }

    /**
     * @dev Returns true if the reentrancy guard is currently set to "entered", which indicates there is a
     * `nonReentrant` function in the call stack.
     */
    function _reentrancyGuardEntered() internal view returns (bool) {
        return _status == ENTERED;
    }
}

contracts/BetCOFI.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "./interfaces/IBetFactoryCOFI.sol";
import "./SCEMScoring.sol";

/// @title BetCOFI - Binary prediction market contract with SCEM payout
/// @notice Users bet on side A or B with a confidence level (1–99).
///         After resolution, winners split the loser pool weighted by their SCEM score.
contract BetCOFI is ReentrancyGuard, Ownable {
    enum BetStatus { ACTIVE, RESOLVING, RESOLVED, UNDETERMINED }
    enum ResolutionType { CRYPTO, STOCKS, NEWS }

    /// @dev Records every individual bet placed for SCEM scoring at resolution time.
    struct TradeSnapshot {
        address trader;
        uint8 probability;   // Confidence in own side (1–99)
        uint256 bondAmount;
        bool onSideA;
    }

    address public immutable creator;
    string public title;
    string public resolutionCriteria;
    string public sideAName;
    string public sideBName;
    uint256 public immutable creationDate;
    uint256 public immutable endDate;
    address public immutable factory;
    IERC20 public immutable token;
    ResolutionType public immutable resolutionType;
    bytes public resolutionData;

    uint256 private constant RESOLUTION_TIMEOUT = 7 days;

    bool public isResolved;
    bool public isSideAWinner;
    BetStatus public status;
    uint256 public resolutionRequestedAt;

    uint256 public totalSideA;
    uint256 public totalSideB;
    mapping(address => uint256) public betsOnSideA;
    mapping(address => uint256) public betsOnSideB;
    mapping(address => bool) public hasClaimed;

    // SCEM
    TradeSnapshot[] public trades;
    mapping(address => uint256) public scemPayout;

    // Resolution results from oracle
    uint256 public resolvedPrice;
    string public winnerValue;

    event BetPlacedOnA(address indexed bettor, uint256 amount, uint8 probability);
    event BetPlacedOnB(address indexed bettor, uint256 amount, uint8 probability);
    event BetResolved(bool sideAWins, uint256 timestamp, uint256 priceValue, string winnerValue);
    event BetUndetermined(uint256 timestamp);
    event WinningsClaimed(address indexed winner, uint256 amount);
    event ResolutionReceived(bool sideAWins);

    constructor(
        address _creator,
        string memory _title,
        string memory _resolutionCriteria,
        string memory _sideAName,
        string memory _sideBName,
        uint256 _endDate,
        address _token,
        address _factory,
        ResolutionType _resolutionType,
        bytes memory _resolutionData
    ) Ownable(_factory) {
        require(_creator != address(0), "Invalid creator address");
        require(_token != address(0), "Invalid token address");
        require(_factory != address(0), "Invalid factory address");
        require(bytes(_title).length > 0, "Title cannot be empty");
        require(bytes(_sideAName).length > 0, "Side A name cannot be empty");
        require(bytes(_sideBName).length > 0, "Side B name cannot be empty");

        creator = _creator;
        title = _title;
        resolutionCriteria = _resolutionCriteria;
        sideAName = _sideAName;
        sideBName = _sideBName;
        creationDate = block.timestamp;
        endDate = _endDate;
        factory = _factory;
        token = IERC20(_token);
        resolutionType = _resolutionType;
        resolutionData = _resolutionData;
        status = BetStatus.ACTIVE;
    }

    // ============ Betting ============

    /// @param probability Confidence in SIDE_A (1–99)
    function betOnSideAViaFactory(address bettor, uint256 amount, uint8 probability) external {
        require(msg.sender == factory, "Only factory can call");
        require(block.timestamp < endDate, "Betting has ended");
        require(status == BetStatus.ACTIVE, "Bet not active");
        require(amount > 0, "Must bet more than 0");
        require(probability >= 1 && probability <= 99, "Probability must be 1-99");

        betsOnSideA[bettor] += amount;
        totalSideA += amount;
        trades.push(TradeSnapshot({ trader: bettor, probability: probability, bondAmount: amount, onSideA: true }));

        emit BetPlacedOnA(bettor, amount, probability);
    }

    /// @param probability Confidence in SIDE_B (1–99)
    function betOnSideBViaFactory(address bettor, uint256 amount, uint8 probability) external {
        require(msg.sender == factory, "Only factory can call");
        require(block.timestamp < endDate, "Betting has ended");
        require(status == BetStatus.ACTIVE, "Bet not active");
        require(amount > 0, "Must bet more than 0");
        require(probability >= 1 && probability <= 99, "Probability must be 1-99");

        betsOnSideB[bettor] += amount;
        totalSideB += amount;
        trades.push(TradeSnapshot({ trader: bettor, probability: probability, bondAmount: amount, onSideA: false }));

        emit BetPlacedOnB(bettor, amount, probability);
    }

    // ============ Resolution ============

    /// @notice Creator calls after endDate to request oracle resolution
    function resolve() external {
        require(
            IBetFactoryCOFI(factory).canResolveBet(msg.sender, creator),
            "Not authorized to resolve"
        );
        require(block.timestamp >= endDate, "Cannot resolve before end date");
        require(status == BetStatus.ACTIVE, "Bet not active");

        uint8 oldStatus = uint8(status);
        status = BetStatus.RESOLVING;
        resolutionRequestedAt = block.timestamp;

        IBetFactoryCOFI(factory).notifyStatusChange(oldStatus, uint8(status));
        IBetFactoryCOFI(factory).forwardResolutionRequest(uint8(resolutionType));
    }

    /// @notice Called by factory when oracle resolution arrives via bridge
    function setResolution(bytes calldata _message) external {
        require(msg.sender == factory, "Only factory can dispatch");

        (
            address betAddress,
            bool sideAWins,
            bool isUndetermined,
            ,
            ,
            uint256 priceValue,
            string memory winnerVal
        ) = abi.decode(_message, (address, bool, bool, uint256, bytes32, uint256, string));

        require(betAddress == address(this), "Response for wrong bet");
        require(status == BetStatus.RESOLVING, "Not awaiting resolution");

        uint8 oldStatus = uint8(status);
        isResolved = true;
        resolvedPrice = priceValue;
        winnerValue = winnerVal;

        if (isUndetermined) {
            status = BetStatus.UNDETERMINED;
            emit BetUndetermined(block.timestamp);
        } else {
            isSideAWinner = sideAWins;
            status = BetStatus.RESOLVED;
            _applyScemPayout();
            emit BetResolved(sideAWins, block.timestamp, priceValue, winnerVal);
        }

        IBetFactoryCOFI(factory).notifyStatusChange(oldStatus, uint8(status));
        emit ResolutionReceived(sideAWins);
    }

    // ============ SCEM Payout ============

    /// @dev Iterates all trades and distributes the losers' pool to winners
    ///      proportionally by their SCEM score × bond.
    ///      O(n) gas — acceptable for hackathon scale.
    function _applyScemPayout() internal {
        bool _sideAWins = isSideAWinner;

        uint256 losersPool = 0;
        int256 totalWeightedScore = 0;
        bool anyWinners = false;

        // Pass 1 — identify losers pool and total winner weighted score
        for (uint256 i = 0; i < trades.length; i++) {
            TradeSnapshot memory t = trades[i];
            bool isWinner = (t.onSideA == _sideAWins);

            if (!isWinner) {
                losersPool += t.bondAmount;
            } else {
                anyWinners = true;
                // r = 100 because winner always predicted their side correctly
                int256 s = SCEMScoring.computeScore(t.probability, 100);
                // s is always > 0 for probability ∈ [1,99] and r = 100
                totalWeightedScore += s * int256(t.bondAmount);
            }
        }

        // Edge case: no one on winning side — refund everyone
        if (!anyWinners) {
            for (uint256 i = 0; i < trades.length; i++) {
                scemPayout[trades[i].trader] += trades[i].bondAmount;
            }
            return;
        }

        // Pass 2 — compute winner payouts
        for (uint256 i = 0; i < trades.length; i++) {
            TradeSnapshot memory t = trades[i];
            bool isWinner = (t.onSideA == _sideAWins);
            if (!isWinner) continue;

            // Bond returned + proportional share of losers pool
            uint256 payout = t.bondAmount;

            if (totalWeightedScore > 0) {
                int256 s = SCEMScoring.computeScore(t.probability, 100);
                if (s > 0) {
                    uint256 share = (losersPool * uint256(s) * t.bondAmount) / uint256(totalWeightedScore);
                    payout += share;
                }
            }

            scemPayout[t.trader] += payout;
        }
    }

    // ============ Claiming ============

    /// @notice Claim winnings (SCEM-weighted) or refund (UNDETERMINED)
    function claim() external nonReentrant {
        require(isResolved, "Bet not resolved yet");
        require(!hasClaimed[msg.sender], "Already claimed");

        uint256 payout = 0;

        if (status == BetStatus.UNDETERMINED) {
            payout = betsOnSideA[msg.sender] + betsOnSideB[msg.sender];
            require(payout > 0, "No bet to refund");
        } else {
            // RESOLVED: SCEM payout precomputed at resolution
            payout = scemPayout[msg.sender];
            require(payout > 0, "No winnings to claim");
        }

        hasClaimed[msg.sender] = true;
        require(token.transfer(msg.sender, payout), "Transfer failed");
        emit WinningsClaimed(msg.sender, payout);
    }

    /// @notice Creator can cancel if oracle doesn't respond within RESOLUTION_TIMEOUT
    function cancelBet() external {
        require(msg.sender == creator, "Only creator can cancel");
        require(status == BetStatus.RESOLVING, "Can only cancel while resolving");
        require(block.timestamp >= resolutionRequestedAt + RESOLUTION_TIMEOUT, "Timeout not reached");

        uint8 oldStatus = uint8(status);
        isResolved = true;
        status = BetStatus.UNDETERMINED;

        IBetFactoryCOFI(factory).notifyStatusChange(oldStatus, uint8(status));
        emit BetUndetermined(block.timestamp);
    }

    // ============ Views ============

    function getInfo() external view returns (
        address _creator,
        string memory _title,
        string memory _resolutionCriteria,
        string memory _sideAName,
        string memory _sideBName,
        uint256 _creationDate,
        uint256 _endDate,
        bool _isResolved,
        bool _isSideAWinner,
        uint256 _totalSideA,
        uint256 _totalSideB,
        uint256 _resolvedPrice,
        string memory _winnerValue
    ) {
        return (
            creator,
            title,
            resolutionCriteria,
            sideAName,
            sideBName,
            creationDate,
            endDate,
            isResolved,
            isSideAWinner,
            totalSideA,
            totalSideB,
            resolvedPrice,
            winnerValue
        );
    }

    function getUserBets(address user) external view returns (uint256 onSideA, uint256 onSideB) {
        return (betsOnSideA[user], betsOnSideB[user]);
    }

    function getTradeCount() external view returns (uint256) {
        return trades.length;
    }

    function calculatePotentialWinnings(address user) external view returns (
        uint256 ifSideAWins,
        uint256 ifSideBWins
    ) {
        uint256 userBetOnA = betsOnSideA[user];
        uint256 userBetOnB = betsOnSideB[user];

        if (userBetOnA > 0 && totalSideA > 0) {
            uint256 winningsShare = totalSideB > 0 ? (userBetOnA * totalSideB) / totalSideA : 0;
            ifSideAWins = userBetOnA + winningsShare;
        }

        if (userBetOnB > 0 && totalSideB > 0) {
            uint256 winningsShare = totalSideA > 0 ? (userBetOnB * totalSideA) / totalSideB : 0;
            ifSideBWins = userBetOnB + winningsShare;
        }
    }
}

contracts/BetFactoryCOFI.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "./BetCOFI.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/// @title BetFactoryCOFI - Factory for deploying prediction markets
/// @notice Creates BetCOFI instances and routes oracle resolutions from GenLayer bridge
contract BetFactoryCOFI is Ownable {
    address public immutable usdcToken;
    address public bridgeReceiver;
    address[] public allBets;
    mapping(address => bool) public deployedBets;
    mapping(address => bool) public approvedCreators;
    mapping(address => bool) public approvedResolvers;

    // Status tracking for frontend queries
    address[] public activeBets;
    address[] public resolvingBets;
    address[] public resolvedBets;
    address[] public undeterminedBets;
    mapping(address => uint256) private betIndexInStatusArray;

    event BetCreated(address indexed betAddress, address indexed creator, string title, uint256 endDate);
    event BetPlaced(address indexed betAddress, address indexed bettor, bool onSideA, uint256 amount);
    event OracleResolutionReceived(address indexed betContract, uint32 sourceChainId);
    event ResolutionRequested(
        address indexed betContract,
        address indexed creator,
        uint8 resolutionType,
        string title,
        string sideAName,
        string sideBName,
        bytes resolutionData,
        uint256 timestamp
    );
    event BridgeReceiverUpdated(address indexed oldReceiver, address indexed newReceiver);
    event CreatorApprovalUpdated(address indexed creator, bool approved);
    event ResolverApprovalUpdated(address indexed resolver, bool approved);
    event BetStatusChanged(address indexed betContract, uint8 oldStatus, uint8 newStatus);

    constructor(address _usdcToken) Ownable(msg.sender) {
        require(_usdcToken != address(0), "Invalid USDC address");
        usdcToken = _usdcToken;
    }

    function setCreatorApproval(address _creator, bool _approved) external onlyOwner {
        approvedCreators[_creator] = _approved;
        emit CreatorApprovalUpdated(_creator, _approved);
    }

    function setResolverApproval(address _resolver, bool _approved) external onlyOwner {
        approvedResolvers[_resolver] = _approved;
        emit ResolverApprovalUpdated(_resolver, _approved);
    }

    function canCreateBet(address _creator) public view returns (bool) {
        return _creator == owner() || approvedCreators[_creator];
    }

    function canResolveBet(address _caller, address _creator) public view returns (bool) {
        return _caller == _creator || _caller == owner() || approvedResolvers[_caller];
    }

    function setBridgeReceiver(address _bridgeReceiver) external onlyOwner {
        require(_bridgeReceiver != address(0), "Invalid bridge receiver");
        address oldReceiver = bridgeReceiver;
        bridgeReceiver = _bridgeReceiver;
        emit BridgeReceiverUpdated(oldReceiver, _bridgeReceiver);
    }

    // ============ Bridge Handling ============

    /// @notice Receives oracle resolution from BridgeReceiver and dispatches to target bet
    function processBridgeMessage(uint32 _sourceChainId, address, bytes calldata _message) external {
        require(msg.sender == bridgeReceiver, "Only bridge receiver");

        (address targetContract, bytes memory data) = abi.decode(_message, (address, bytes));
        require(deployedBets[targetContract], "Unknown bet contract");

        BetCOFI(targetContract).setResolution(data);
        emit OracleResolutionReceived(targetContract, _sourceChainId);
    }

    /// @notice Called by BetCOFI.resolve() - emits event for oracle service to pick up
    function forwardResolutionRequest(uint8 _resolutionType) external {
        require(deployedBets[msg.sender], "Not a deployed bet");

        BetCOFI bet = BetCOFI(msg.sender);
        address creator = bet.creator();
        string memory betTitle = bet.title();
        string memory sideA = bet.sideAName();
        string memory sideB = bet.sideBName();
        bytes memory data = bet.resolutionData();

        emit ResolutionRequested(
            msg.sender,
            creator,
            _resolutionType,
            betTitle,
            sideA,
            sideB,
            data,
            block.timestamp
        );
    }

    /// @notice Called by BetCOFI when status changes
    function notifyStatusChange(uint8 _oldStatus, uint8 _newStatus) external {
        require(deployedBets[msg.sender], "Not a deployed bet");

        // Remove from old status array
        _removeFromStatusArray(msg.sender, BetCOFI.BetStatus(_oldStatus));

        // Add to new status array
        _addToStatusArray(msg.sender, BetCOFI.BetStatus(_newStatus));

        emit BetStatusChanged(msg.sender, _oldStatus, _newStatus);
    }

    function _removeFromStatusArray(address bet, BetCOFI.BetStatus status) internal {
        address[] storage arr = _getStatusArray(status);
        uint256 index = betIndexInStatusArray[bet];
        uint256 lastIndex = arr.length - 1;

        if (index != lastIndex) {
            address lastBet = arr[lastIndex];
            arr[index] = lastBet;
            betIndexInStatusArray[lastBet] = index;
        }

        arr.pop();
    }

    function _addToStatusArray(address bet, BetCOFI.BetStatus status) internal {
        address[] storage arr = _getStatusArray(status);
        betIndexInStatusArray[bet] = arr.length;
        arr.push(bet);
    }

    function _getStatusArray(BetCOFI.BetStatus status) internal view returns (address[] storage) {
        if (status == BetCOFI.BetStatus.ACTIVE) return activeBets;
        if (status == BetCOFI.BetStatus.RESOLVING) return resolvingBets;
        if (status == BetCOFI.BetStatus.RESOLVED) return resolvedBets;
        return undeterminedBets;
    }

    // ============ Bet Management ============

    function createBet(
        string memory title,
        string memory resolutionCriteria,
        string memory sideAName,
        string memory sideBName,
        uint256 endDate,
        uint8 resolutionType,
        bytes memory resolutionData
    ) external returns (address) {
        require(canCreateBet(msg.sender), "Not authorized to create bets");
        require(resolutionType <= 2, "Invalid resolution type");

        BetCOFI bet = new BetCOFI(
            msg.sender,
            title,
            resolutionCriteria,
            sideAName,
            sideBName,
            endDate,
            usdcToken,
            address(this),
            BetCOFI.ResolutionType(resolutionType),
            resolutionData
        );

        address betAddress = address(bet);

        allBets.push(betAddress);
        deployedBets[betAddress] = true;

        // Add to active bets
        betIndexInStatusArray[betAddress] = activeBets.length;
        activeBets.push(betAddress);

        emit BetCreated(betAddress, msg.sender, title, endDate);

        return betAddress;
    }

    /// @notice Users place bets through factory (single USDC approval for all bets)
    /// @param probability Confidence in the chosen side (1–99). Used for SCEM scoring at payout.
    function placeBet(address betAddress, bool onSideA, uint256 amount, uint8 probability) external {
        require(deployedBets[betAddress], "Bet not from this factory");
        require(amount > 0, "Amount must be greater than 0");
        require(probability >= 1 && probability <= 99, "Probability must be 1-99");

        require(IERC20(usdcToken).transferFrom(msg.sender, betAddress, amount), "USDC transfer failed");

        BetCOFI bet = BetCOFI(betAddress);
        if (onSideA) {
            bet.betOnSideAViaFactory(msg.sender, amount, probability);
        } else {
            bet.betOnSideBViaFactory(msg.sender, amount, probability);
        }

        emit BetPlaced(betAddress, msg.sender, onSideA, amount);
    }

    /// @notice Convenience wrapper for creating NEWS-type prediction markets
    /// @param question The question to be resolved (e.g. "Did X happen?")
    /// @param evidenceUrl Primary URL for GenLayer validators to fetch evidence from
    function createNewsBet(
        string memory title,
        string memory question,
        string memory evidenceUrl,
        string memory sideAName,
        string memory sideBName,
        uint256 endDate
    ) external returns (address) {
        require(canCreateBet(msg.sender), "Not authorized to create bets");
        require(bytes(question).length > 0, "Question cannot be empty");
        require(bytes(evidenceUrl).length > 0, "Evidence URL cannot be empty");

        bytes memory resolutionData = abi.encode(question, evidenceUrl);

        BetCOFI bet = new BetCOFI(
            msg.sender,
            title,
            question,
            sideAName,
            sideBName,
            endDate,
            usdcToken,
            address(this),
            BetCOFI.ResolutionType.NEWS,
            resolutionData
        );

        address betAddress = address(bet);
        allBets.push(betAddress);
        deployedBets[betAddress] = true;
        betIndexInStatusArray[betAddress] = activeBets.length;
        activeBets.push(betAddress);

        emit BetCreated(betAddress, msg.sender, title, endDate);

        return betAddress;
    }

    function getAllBets() external view returns (address[] memory) {
        return allBets;
    }

    function getBetCount() external view returns (uint256) {
        return allBets.length;
    }

    function isLegitBet(address betAddress) external view returns (bool) {
        return deployedBets[betAddress];
    }

    // ============ Status Query Functions ============

    function getActiveBets() external view returns (address[] memory) {
        return activeBets;
    }

    function getResolvingBets() external view returns (address[] memory) {
        return resolvingBets;
    }

    function getResolvedBets() external view returns (address[] memory) {
        return resolvedBets;
    }

    function getUndeterminedBets() external view returns (address[] memory) {
        return undeterminedBets;
    }

    function getBetsByStatus(uint8 status) external view returns (address[] memory) {
        if (status == uint8(BetCOFI.BetStatus.ACTIVE)) return activeBets;
        if (status == uint8(BetCOFI.BetStatus.RESOLVING)) return resolvingBets;
        if (status == uint8(BetCOFI.BetStatus.RESOLVED)) return resolvedBets;
        if (status == uint8(BetCOFI.BetStatus.UNDETERMINED)) return undeterminedBets;
        revert("Invalid status");
    }

    function getActiveBetsCount() external view returns (uint256) {
        return activeBets.length;
    }

    function getResolvingBetsCount() external view returns (uint256) {
        return resolvingBets.length;
    }

    function getResolvedBetsCount() external view returns (uint256) {
        return resolvedBets.length;
    }

    function getUndeterminedBetsCount() external view returns (uint256) {
        return undeterminedBets.length;
    }
}

contracts/interfaces/IBetFactoryCOFI.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

interface IBetFactoryCOFI {
    function forwardResolutionRequest(uint8 resolutionType) external;
    function notifyStatusChange(uint8 oldStatus, uint8 newStatus) external;
    function canResolveBet(address caller, address creator) external view returns (bool);
}

contracts/mocks/MockUSDL.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MockUSDL is ERC20, Ownable {
    uint256 public constant MINT_LIMIT = 100 * 10**6; // 100 tokens (6 decimals)
    uint256 public constant MINT_PERIOD = 24 hours;

    mapping(address => uint256) public lastMintTimestamp;
    mapping(address => uint256) public mintedInPeriod;
    mapping(address => bool) public admins;
    mapping(address => bool) public blockedAddresses;

    event AdminUpdated(address indexed account, bool status);
    event AddressBlocked(address indexed account, bool blocked);

    constructor() ERC20("Mock USDL", "USDL") Ownable(msg.sender) {}

    /// @notice Add or remove an address from admin list (can mint unlimited)
    function setAdmin(address account, bool status) external onlyOwner {
        admins[account] = status;
        emit AdminUpdated(account, status);
    }

    /// @notice Block or unblock an address from minting (callable by admins)
    function setBlocked(address account, bool blocked) external {
        require(isAdmin(msg.sender), "Not authorized");
        blockedAddresses[account] = blocked;
        emit AddressBlocked(account, blocked);
    }

    /// @notice Check if an address is an admin (owner or in admin list)
    function isAdmin(address account) public view returns (bool) {
        return account == owner() || admins[account];
    }

    /// @notice Mint tokens to an address (admins bypass rate limit)
    function mint(address to, uint256 amount) external {
        require(!blockedAddresses[to], "Address is blocked");
        if (!isAdmin(msg.sender)) {
            _enforceRateLimit(to, amount);
        }
        _mint(to, amount);
    }

    /// @notice Faucet function - mint 100 tokens to caller
    function drip() external {
        require(!blockedAddresses[msg.sender], "Address is blocked");
        _enforceRateLimit(msg.sender, MINT_LIMIT);
        _mint(msg.sender, MINT_LIMIT);
    }

    function _enforceRateLimit(address to, uint256 amount) internal {
        if (block.timestamp >= lastMintTimestamp[to] + MINT_PERIOD) {
            mintedInPeriod[to] = 0;
            lastMintTimestamp[to] = block.timestamp;
        }

        require(
            mintedInPeriod[to] + amount <= MINT_LIMIT,
            "Exceeds 24h mint limit of 100 tokens"
        );

        mintedInPeriod[to] += amount;
    }

    function decimals() public pure override returns (uint8) {
        return 6;
    }

    /// @notice Check remaining mint allowance for an address
    function remainingMintAllowance(address account) external view returns (uint256) {
        if (block.timestamp >= lastMintTimestamp[account] + MINT_PERIOD) {
            return MINT_LIMIT;
        }
        return MINT_LIMIT > mintedInPeriod[account]
            ? MINT_LIMIT - mintedInPeriod[account]
            : 0;
    }

    /// @notice Get timestamp when rate limit resets for an address
    function nextResetTime(address account) external view returns (uint256) {
        if (lastMintTimestamp[account] == 0) {
            return 0;
        }
        return lastMintTimestamp[account] + MINT_PERIOD;
    }
}

contracts/SCEMScoring.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

/// @title SCEMScoring - Strictly Proper Scoring Rule (Quadratic)
/// @notice Implements S(r, q) = 2·q·r - q²
/// @dev q and r are integers in [0,100]. Score is in units of percent².
///      q = confidence in predicted outcome (1–99)
///      r = 100 if prediction was correct, 0 otherwise
///      Result is always > 0 for any q ∈ [1,99] when r = 100
library SCEMScoring {
    /// @param q Predicted confidence (1–99). Relative to the bettor's chosen side.
    /// @param r 100 if prediction correct, 0 if incorrect.
    /// @return Quadratic scoring rule value. Positive = rewarded, negative = penalized.
    function computeScore(uint8 q, uint8 r) internal pure returns (int256) {
        int256 qi = int256(uint256(q));
        int256 ri = int256(uint256(r));
        return 2 * qi * ri - qi * qi;
    }
}

